
"use client"

import { useState, useEffect, useRef, useMemo } from "react";
import { BottomNav } from "@/components/layout/bottom-nav";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Card } from "@/components/ui/card";
import { 
  Gauge, Zap, Radio, ShieldAlert, Activity, WifiOff, Palette, 
  Camera, CarFront, AlertTriangle, Loader2 
} from "lucide-react";
import { cn } from "@/lib/utils";
import { useToast } from "@/hooks/use-toast";

// Funksioni për llogaritjen e distancës midis dy pikave (Haversine)
function getDistance(lat1: number, lon1: number, lat2: number, lon2: number) {
  const R = 6371e3; // rrezja e tokës në metra
  const phi1 = (lat1 * Math.PI) / 180;
  const phi2 = (lat2 * Math.PI) / 180;
  const deltaPhi = ((lat2 - lat1) * Math.PI) / 180;
  const deltaLambda = ((lon2 - lon1) * Math.PI) / 180;

  const a =
    Math.sin(deltaPhi / 2) * Math.sin(deltaPhi / 2) +
    Math.cos(phi1) * Math.cos(phi2) * Math.sin(deltaLambda / 2) * Math.sin(deltaLambda / 2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));

  return R * c; // në metra
}

// Simulimi i alarmeve për detektim (në prodhim këto do të vinin nga Firestore)
const MOCK_ALERTS = [
  { id: 1, type: "Radar", lat: 42.6629, lng: 21.1655, location: "Prishtinë, Qendër" },
  { id: 2, type: "Polici", lat: 42.215, lng: 21.125, location: "Autostrada, Ferizaj" },
  { id: 3, type: "Kontrollë", lat: 42.231, lng: 20.735, location: "Tranzit, Prizren" },
];

type SpeedoTheme = 'default' | 'm3_modern' | 'rs_performance' | 'porsche';
type ReportType = 'Radar' | 'Polici' | 'Kontrollë';

export default function DashboardPage() {
  const [speed, setSpeed] = useState(0);
  const [isDriving, setIsDriving] = useState(false);
  const [peakSpeed, setPeakSpeed] = useState(0);
  const [hasGps, setHasGps] = useState(false);
  const [mounted, setMounted] = useState(false);
  const [theme, setTheme] = useState<SpeedoTheme>('m3_modern');
  const [isReporting, setIsReporting] = useState<ReportType | null>(null);
  const { toast } = useToast();
  
  const [currentCoords, setCurrentCoords] = useState<{ lat: number; lng: number } | null>(null);
  const lastPos = useRef<{ lat: number; lng: number; timestamp: number } | null>(null);
  const wakeLockRef = useRef<any>(null);

  useEffect(() => {
    setMounted(true);
  }, []);

  // Llogaritja e alarmit më të afërt
  const nearestAlert = useMemo(() => {
    if (!currentCoords) return null;
    
    const alertsWithDist = MOCK_ALERTS.map(alert => ({
      ...alert,
      distance: getDistance(currentCoords.lat, currentCoords.lng, alert.lat, alert.lng)
    }));

    // Gjejmë alarmin më të afërt brenda 2km
    const nearby = alertsWithDist.filter(a => a.distance < 2000);
    if (nearby.length === 0) return null;
    
    return nearby.sort((a, b) => a.distance - b.distance)[0];
  }, [currentCoords]);

  // Wake Lock API - Mbajtja e ekranit ndezur
  useEffect(() => {
    const requestWakeLock = async () => {
      try {
        if ('wakeLock' in navigator && isDriving) {
          wakeLockRef.current = await (navigator as any).wakeLock.request('screen');
        }
      } catch (err: any) {
        // Silently fail if wake lock is not supported
      }
    };

    const releaseWakeLock = async () => {
      if (wakeLockRef.current !== null) {
        try {
          await wakeLockRef.current.release();
          wakeLockRef.current = null;
        } catch (e) {
          // Ignore
        }
      }
    };

    if (isDriving) {
      requestWakeLock();
    } else {
      releaseWakeLock();
    }

    return () => {
      releaseWakeLock();
    };
  }, [isDriving]);

  useEffect(() => {
    let watchId: number;

    if (isDriving && mounted) {
      if (!navigator.geolocation) return;

      watchId = navigator.geolocation.watchPosition(
        (position) => {
          setHasGps(true);
          const { latitude, longitude } = position.coords;
          const timestamp = position.timestamp;
          setCurrentCoords({ lat: latitude, lng: longitude });
          
          let currentKmh = 0;
          const directMps = position.coords.speed;

          if (directMps !== null && directMps !== undefined && directMps >= 0) {
            currentKmh = Math.round(directMps * 3.6);
          } else if (lastPos.current) {
            const distance = getDistance(lastPos.current.lat, lastPos.current.lng, latitude, longitude);
            const timeDiff = (timestamp - lastPos.current.timestamp) / 1000;
            if (timeDiff > 0 && distance > 0.1) {
              currentKmh = Math.round((distance / timeDiff) * 3.6);
            }
          }

          if (currentKmh > 420) return;

          setSpeed(currentKmh);
          if (currentKmh > peakSpeed) setPeakSpeed(currentKmh);
          lastPos.current = { lat: latitude, lng: longitude, timestamp };
        },
        (error) => {
          setHasGps(false);
          // Detailed logging to help identify permission vs timeout issues
          if (error.code === 3) {
            console.warn("GPS Timeout: Po kërkohet për sinjal më të fortë...");
          } else {
            console.error("GPS Error:", error.code, error.message);
          }
        },
        { enableHighAccuracy: true, timeout: 5000, maximumAge: 0 }
      );
    } else {
      setSpeed(0);
      setHasGps(false);
      lastPos.current = null;
    }

    return () => {
      if (watchId) navigator.geolocation.clearWatch(watchId);
    };
  }, [isDriving, peakSpeed, mounted]);

  const handleQuickReport = (type: ReportType) => {
    setIsReporting(type);
    // Këtu do të dërgohej raportimi në Firestore
    setTimeout(() => {
      setIsReporting(null);
      toast({
        title: "Raportimi u krye!",
        description: `${type} u regjistrua në lokacionin tuaj.`,
      });
    }, 1500);
  };

  const cycleTheme = () => {
    const themes: SpeedoTheme[] = ['m3_modern', 'rs_performance', 'porsche', 'default'];
    const currentIndex = themes.indexOf(theme);
    const nextIndex = (currentIndex + 1) % themes.length;
    setTheme(themes[nextIndex]);
  };

  if (!mounted) return <div className="min-h-screen bg-background" />;

  return (
    <div className="flex flex-col min-h-screen bg-background text-foreground pb-24 overflow-hidden safe-bottom">
      {/* Header Status Bar */}
      <div className="p-6 flex items-center justify-between z-20">
        <div className="flex items-center gap-2">
          {hasGps ? (
            <Activity className="w-4 h-4 text-accent animate-pulse" />
          ) : (
            <WifiOff className="w-4 h-4 text-destructive" />
          )}
          <span className={cn(
            "text-[10px] font-bold tracking-widest uppercase neon-text",
            hasGps ? "text-accent" : "text-muted-foreground"
          )}>
            GPS: {hasGps ? "AKTIV" : "DUKE PRITUR..."}
          </span>
        </div>
        
        <div className="flex items-center gap-3">
          <Button 
            variant="outline" 
            size="icon" 
            onClick={cycleTheme}
            className="w-10 h-10 rounded-xl glass border-white/10"
          >
            <Palette className="w-5 h-5 text-accent" />
          </Button>
          <Badge variant="outline" className="bg-red-500/10 border-red-500/20 text-red-500 text-[10px] font-bold flex items-center gap-1">
            <ShieldAlert className="w-3 h-3" />
            ANTI-CHEAT
          </Badge>
        </div>
      </div>

      {/* Main Container */}
      <div className="flex-1 flex flex-col items-center justify-center relative px-6">
        {/* Speedometer */}
        <div className="relative w-full aspect-square flex items-center justify-center">
          {theme === 'm3_modern' && (
            <div className="w-full h-full relative flex items-center justify-center">
              <div className="absolute inset-0 flex items-center justify-center">
                <div className="absolute inset-0 border-[10px] border-zinc-800 rounded-[40px] rotate-[-15deg] opacity-20" />
                <div className="absolute left-0 h-full w-24 bg-gradient-to-r from-blue-600/20 to-transparent" style={{ clipPath: 'polygon(0 0, 100% 20%, 100% 80%, 0 100%)' }} />
                <div className="absolute right-0 h-full w-24 bg-gradient-to-l from-red-600/20 to-transparent" style={{ clipPath: 'polygon(100% 0, 0 20%, 0 80%, 100% 100%)' }} />
                <div className="absolute left-4 top-1/2 -translate-y-1/2 flex flex-col items-end gap-1">
                  {[...Array(12)].map((_, i) => (
                    <div key={i} className={cn("w-12 h-1.5 skew-x-[-30deg] transition-all duration-300", (12 - i) * 25 <= speed ? "bg-blue-500 shadow-[0_0_10px_#3b82f6]" : "bg-white/5")} />
                  ))}
                </div>
                <div className="absolute right-4 top-1/2 -translate-y-1/2 flex flex-col items-start gap-1">
                  {[...Array(12)].map((_, i) => (
                    <div key={i} className={cn("w-12 h-1.5 skew-x-[30deg] transition-all duration-300", (12 - i) * 30 <= speed + 50 ? "bg-red-600 shadow-[0_0_10px_#ef4444]" : "bg-white/5")} />
                  ))}
                </div>
              </div>
              <div className="flex flex-col items-center z-10">
                <span className="text-9xl font-black italic tracking-tighter text-white leading-none drop-shadow-2xl">{speed}</span>
                <div className="flex items-center gap-1.5 mt-2">
                  <div className="w-8 h-2 bg-[#0038A8] rounded-full" /><div className="w-8 h-2 bg-[#0062FF] rounded-full" /><div className="w-8 h-2 bg-[#FF0000] rounded-full" />
                </div>
                <span className="text-xs font-black text-zinc-500 uppercase tracking-[0.3em] mt-2">M PERFORMANCE</span>
              </div>
            </div>
          )}
          {theme === 'rs_performance' && (
            <div className="w-full h-full relative flex items-center justify-center bg-[#050505] rounded-[3rem] border border-white/5 overflow-hidden">
              <div className="absolute inset-0 grid grid-cols-6 grid-rows-6 opacity-5">{[...Array(36)].map((_, i) => <div key={i} className="border border-white/10" />)}</div>
              <div className="absolute bottom-0 w-full h-[60%] flex flex-col items-center justify-end pb-12">
                <div className="w-[80%] h-2 bg-zinc-900 rounded-full overflow-hidden mb-4">
                  <div className="h-full bg-red-600 shadow-[0_0_20px_red] transition-all duration-300" style={{ width: `${Math.min((speed / 320) * 100, 100)}%` }} />
                </div>
                <div className="flex justify-between w-[80%] text-[8px] font-bold text-zinc-600 uppercase tracking-widest"><span>0 km/h</span><span>160</span><span>320</span></div>
              </div>
              <div className="flex flex-col items-center"><span className="text-[10rem] font-black text-white leading-none tracking-tighter">{speed}</span><div className="flex items-center gap-3"><Badge className="bg-red-600 text-white font-black italic rounded-none px-4 py-1 text-sm border-none">RS</Badge><span className="text-sm font-bold text-zinc-400 tracking-[0.2em] uppercase">V-MAX</span></div></div>
            </div>
          )}
          {theme === 'porsche' && (
            <div className="w-full h-full relative flex items-center justify-center bg-zinc-100 rounded-full border-[12px] border-zinc-300 shadow-2xl">
              <div className="absolute inset-4 rounded-full border-2 border-zinc-200" /><div className="absolute w-1 h-full bg-zinc-400/20" /><div className="absolute h-1 w-full bg-zinc-400/20" />
              <div className="absolute w-1.5 h-40 bg-red-600 origin-bottom bottom-1/2 left-1/2 -translate-x-1/2 transition-transform duration-200 ease-out z-20 shadow-lg" style={{ transform: `translateX(-50%) rotate(${-120 + (Math.min(speed, 350) / 350) * 240}deg)` }}><div className="w-5 h-5 bg-zinc-900 rounded-full absolute -bottom-2.5 -left-1.5 border-2 border-zinc-400" /></div>
              <div className="flex flex-col items-center z-10 bg-zinc-900 px-8 py-4 rounded-3xl border-4 border-zinc-800 shadow-2xl"><span className="text-7xl font-black text-white font-sans leading-none">{speed}</span><span className="text-xs font-bold text-zinc-500 uppercase tracking-widest mt-1">KM/H</span></div>
              <div className="absolute top-20 font-black text-zinc-800 text-2xl italic tracking-tighter">PORSCHE</div>
            </div>
          )}
          {theme === 'default' && (
            <div className="relative w-80 h-80 flex items-center justify-center">
              <div className="absolute inset-0 rounded-full border-[12px] border-white/5 border-t-accent border-r-accent/40 transition-all duration-300 ease-out" style={{ transform: `rotate(${135 + (Math.min(speed, 300) / 300) * 270}deg)` }} />
              <div className="absolute inset-4 rounded-full border border-accent/20 neon-glow" />
              <div className="flex flex-col items-center z-10"><span className="text-8xl font-black italic tracking-tighter neon-text">{speed}</span><span className="text-sm font-bold tracking-[0.2em] text-muted-foreground uppercase -mt-2">km/h</span></div>
            </div>
          )}
        </div>

        {/* Start/Stop Button (Moved Higher) */}
        <div className="w-full mt-4 mb-4">
          <Button 
            onClick={() => setIsDriving(!isDriving)}
            className={cn(
              "w-full h-20 rounded-[2rem] font-black text-xl uppercase italic tracking-tighter transition-all duration-500 shadow-2xl",
              isDriving ? "bg-red-500 hover:bg-red-600 text-white shadow-red-500/20" : "bg-accent hover:bg-accent/80 text-background neon-glow"
            )}
          >
            {isDriving ? "NDALO MATJEN" : "FILLO MATJEN"}
          </Button>
        </div>

        {/* Dynamic Radar Section */}
        <div className="w-full">
          {nearestAlert ? (
            <div className="glass rounded-[2rem] p-5 border-red-500/30 animate-pulse-glow bg-red-500/5">
              <div className="flex items-center gap-4 mb-4">
                <div className="w-12 h-12 rounded-2xl bg-red-500/20 flex items-center justify-center">
                  <AlertTriangle className="text-red-500 w-7 h-7" />
                </div>
                <div>
                  <p className="text-[10px] font-black text-red-500 uppercase tracking-[0.2em] mb-1">KUJDES: {nearestAlert.type.toUpperCase()} AFËR</p>
                  <p className="text-base font-bold truncate">{nearestAlert.location}</p>
                  <p className="text-[10px] font-bold text-muted-foreground mt-1">DISTANCA: {Math.round(nearestAlert.distance)} METRA</p>
                </div>
              </div>
            </div>
          ) : (
            <div className="glass rounded-[2rem] p-5 border-accent/20 flex items-center gap-5">
              <div className="w-12 h-12 rounded-2xl bg-accent/10 flex items-center justify-center">
                <Radio className="text-accent w-7 h-7" />
              </div>
              <div>
                <p className="text-[10px] font-black text-accent uppercase tracking-[0.2em] mb-1">RRUGËT E KOSOVËS: E PASTRË</p>
                <p className="text-sm font-bold">Nuk u detektua asnjë radar afër.</p>
              </div>
            </div>
          )}
        </div>

        {/* Quick Report Panel */}
        <div className="mt-6 w-full space-y-3">
          <p className="text-[9px] font-black text-muted-foreground uppercase tracking-[0.2em] text-center">RAPORTIM I SHPEJTË NË DASHBOARD</p>
          <div className="grid grid-cols-3 gap-3">
            <Button 
              onClick={() => handleQuickReport('Radar')}
              disabled={!!isReporting}
              className="h-16 flex flex-col gap-1 rounded-2xl bg-white/5 border border-white/10 hover:bg-red-500/20 hover:border-red-500/40 text-white"
            >
              {isReporting === 'Radar' ? <Loader2 className="w-4 h-4 animate-spin text-red-500" /> : <Camera className="w-5 h-5 text-red-500" />}
              <span className="text-[8px] font-black italic">RADAR</span>
            </Button>
            <Button 
              onClick={() => handleQuickReport('Polici')}
              disabled={!!isReporting}
              className="h-16 flex flex-col gap-1 rounded-2xl bg-white/5 border border-white/10 hover:bg-blue-500/20 hover:border-blue-500/40 text-white"
            >
              {isReporting === 'Polici' ? <Loader2 className="w-4 h-4 animate-spin text-blue-500" /> : <ShieldAlert className="w-5 h-5 text-blue-500" />}
              <span className="text-[8px] font-black italic">POLICI</span>
            </Button>
            <Button 
              onClick={() => handleQuickReport('Kontrollë')}
              disabled={!!isReporting}
              className="h-16 flex flex-col gap-1 rounded-2xl bg-white/5 border border-white/10 hover:bg-zinc-700 text-white"
            >
              {isReporting === 'Kontrollë' ? <Loader2 className="w-4 h-4 animate-spin" /> : <CarFront className="w-5 h-5 text-zinc-400" />}
              <span className="text-[8px] font-black italic">KONTROLLË</span>
            </Button>
          </div>
        </div>
      </div>

      <BottomNav />
    </div>
  );
}
